external_knowledge:
; Ad creatives refer to the advertisements displayed on various platforms; 
; Platforms include social media sites such as Facebook, Instagram, and Twitter; 
; Results include metrics such as link clicks and conversions; 
; Impressions by platform refer to the number of times the ad was displayed on a particular platform.

sql:
SELECT campaign_id
FROM campaigns
ORDER BY campaign_id;

SELECT budget AS total_budget
FROM ad_sets
WHERE ad_set_id = 0;

SELECT COUNT(ad_creative_id) AS num_ad_creatives
FROM ad_creatives
WHERE created_by = 7002;

SELECT COUNT(*) AS ad_set_count
FROM ad_sets
WHERE campaign_id = 1;
